# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3, HTTPProvider

app = Flask(__name__)

w3 = Web3(HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

def verify_signature(message, signature, address):
    message_hash = w3.solidityKeccak(['string'], [message])
    signed_address = w3.eth.account.recoverHash(message_hash, signature=signature)
    return signed_address.lower() == address.lower()

@app.route('/authenticate', methods=['POST'])
def authenticate():
    data = request.json
    message = data.get('message')
    signature = data.get('signature')
    address = data.get('address')

    if not message or not signature or not address:
        return jsonify({'success': False, 'error': 'Invalid input'}), 400

    is_valid = verify_signature(message, signature, address)

    if is_valid:
        return jsonify({'success': True, 'address': address}), 200
    else:
        return jsonify({'success': False, 'error': 'Invalid signature'}), 401

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)